import React from 'react'

const Player = ({stat}) => {
    return (
        <div id="player">
            <i className="fas fa-star fa-2x"></i>
            <span className="title"> {stat.fullName}</span>
            <div id="bio">
                {stat.imageURL!==null&&stat.imageURL!==undefined?<img src={stat.imageURL} alt="playerimage" className="profile-pic"></img>:<img src="https://image.flaticon.com/icons/png/512/149/149071.png" alt="playerimage" className="profile-pic"></img>}
                {stat.profile!==""?<h1 className="secondary">{stat.profile}</h1>:<h1 className="secondary">Profile Deatils haven't been uploaded yet.</h1>}
            </div>
            <div className="grid">
                <div id="info">
                    <h1 >Personal Deatils :</h1>
                    <div className="info-grid">
                        <p className="secondary">Name</p>
                        <p className="secondary">{stat.name}</p>
                    </div>
                    <div className="info-grid">
                        <p className="secondary">Full Name</p>
                        <p className="secondary">{stat.fullName}</p>
                    </div>
                    <div className="info-grid">
                        <p className="secondary">Age</p>
                        <p className="secondary">{stat.currentAge}</p>
                    </div>
                    <div className="info-grid">
                        <p className="secondary">Born</p>
                        <p className="secondary">{stat.born}</p>
                    </div>
                </div>
                <div id="cric-info">
                    <h1 >Player Deatils :</h1>
                    <div className="info-grid">
                            <p className="secondary">Batting Style</p>
                            <p className="secondary">{stat.battingStyle}</p>
                        </div>
                        <div className="info-grid">
                            <p className="secondary">Bowling Style</p>
                            <p className="secondary">{stat.bowlingStyle}</p>
                        </div>
                        <div className="info-grid">
                            <p className="secondary">Role</p>
                            <p className="secondary">{stat.playingRole}</p>
                        </div>
                        <div className="info-grid">
                            <p className="secondary">Team</p>
                            <p className="secondary">{stat.majorTeams.substr(0,stat.majorTeams.indexOf(','))}</p>
                        </div>
                        
                    </div>
                <div id="batting-stats">
                    <h1>Batting Stats : </h1>
                    <div className="stats">
                        <div className="formats">
                            <p className="secondary">Format</p>
                            <p className="secondary">Runs</p>
                            <p className="secondary">Highest</p>
                            <p className="secondary">Average</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">ODIs</p>
                            <p className="secondary">{stat.data.batting.ODIs?stat.data.batting.ODIs.Runs:"-"}</p>
                            <p className="secondary">{stat.data.batting.ODIs?stat.data.batting.ODIs.HS:"-"}</p>
                            <p className="secondary">{stat.data.batting.ODIs?stat.data.batting.ODIs.Ave:"-"}</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">T20s</p>
                            <p className="secondary">{stat.data.batting.T20Is?stat.data.batting.T20Is.Runs:"-"}</p>
                            <p className="secondary">{stat.data.batting.T20Is?stat.data.batting.T20Is.HS:"-"}</p>
                            <p className="secondary">{stat.data.batting.T20Is?stat.data.batting.T20Is.Ave:"-"}</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">Tests</p>
                            <p className="secondary">{stat.data.batting.tests?stat.data.batting.tests.Runs:"-"}</p>
                            <p className="secondary">{stat.data.batting.tests?stat.data.batting.tests.HS:"-"}</p>
                            <p className="secondary">{stat.data.batting.tests?stat.data.batting.tests.Ave:"-"}</p>
                        </div>
                    </div>
                </div>
                <div id="bowling-stats">
                    <h1>Bowling Stats : </h1>
                    <div className="stats">
                    <div className="formats">
                            <p className="secondary">Format</p>
                            <p className="secondary">Wickets</p>
                            <p className="secondary">Best</p>
                            <p className="secondary">Economy</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">ODIs</p>
                            <p className="secondary">{stat.data.bowling.ODIs?stat.data.bowling.ODIs.Wkts:"-"}</p>
                            <p className="secondary">{stat.data.bowling.ODIs?stat.data.bowling.ODIs.BBI:"-"}</p>
                            <p className="secondary">{stat.data.bowling.ODIs?stat.data.bowling.ODIs.Econ:"-"}</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">T20s</p>
                            <p className="secondary">{stat.data.bowling.T20Is?stat.data.bowling.T20Is.Wkts:"-"}</p>
                            <p className="secondary">{stat.data.bowling.T20Is?stat.data.bowling.T20Is.BBI:"-"}</p>
                            <p className="secondary">{stat.data.bowling.T20Is?stat.data.bowling.T20Is.Econ:"-"}</p>
                        </div>
                        <div className="formats">
                            <p className="secondary">Tests</p>
                            <p className="secondary">{stat.data.bowling.tests?stat.data.bowling.tests.Wkts:"-"}</p>
                            <p className="secondary">{stat.data.bowling.tests?stat.data.bowling.tests.BBI:"-"}</p>
                            <p className="secondary">{stat.data.bowling.tests?stat.data.bowling.tests.Econ:"-"}</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

export default Player
