import React,{useState,useEffect} from 'react'
import Score from './score';
import Loading from './loading';
const Scorecard = ({livmatches}) => {

    const [scorecard, setScorecard] = useState([]);
    const fetchScore=async(id)=>{
        const res = await fetch(`https://cricapi.com/api/cricketScore?apikey=9HwJ4tbaXGc3nqnwsg4bOREiuwk2&unique_id=${id}`);
        const resdata = await res.json();
        const array=scorecard;
        array.push(resdata);
        setScorecard([...array]);
    }
    useEffect(()=>{
        livmatches.forEach((match)=>{fetchScore(match.unique_id)});
        // eslint-disable-next-line
    },[]);
    return (
        <div id="liv-matches">
            <i className="fas fa-satellite-dish fa-2x"></i>
            <span className="primary">Live Scores</span>
            {scorecard.length===livmatches.length?
            <div id="score-cards">
                {livmatches.map((x,index)=><Score scorecard={scorecard[index]}/>)}
            </div>:null
            }
            {scorecard.length===0?<Loading/>:null}
        </div>
    )
}

export default Scorecard
