import React from 'react';
import {useState} from 'react';
import Player from './player';
import Players from './players';
import Alert from './alert';
import Loading from './loading';
const PlayerSearch = () => {
    const [players, setPlayers] = useState(null);
    const [stat, setStat] = useState(null);
    const [userInput, setUserInput] = useState('');
    const [loading, setLoading] = useState(false);
    const onSubmit = (e)=>{
        e.preventDefault();
        const playerName=document.getElementById("playername").value;
        if(playerName!=='' && playerName.match(/^[0-9]+$/)===null)
        {
            setLoading(true);
            setStat(null);
            getPlayers(playerName);
            document.getElementById("playername").value='';
            setUserInput(playerName);
        }
        else{
            setUserInput(null);
            setTimeout(()=>{
                setUserInput('');
            },2000)
        }
    }
    const getPlayers= async (playerName)=>{
        const res = await fetch(`https://cricapi.com/api/playerFinder?apikey=9HwJ4tbaXGc3nqnwsg4bOREiuwk2&name=${playerName}`);
        const resdata= await res.json();
        setLoading(false);       
        setPlayers(resdata.data);
    }
    const getPlayerStat = async (pid)=>{
        setLoading(true);
        const res = await fetch(`https://cricapi.com/api/playerStats?apikey=9HwJ4tbaXGc3nqnwsg4bOREiuwk2&pid=${pid}`);
        const resdata = await res.json();
        setLoading(false);
        setStat(resdata);
    }
    return (
        <div id="player-search">
            <i className="fas fa-search fa-2x"> </i>
             <span className="primary"> Players Stats :</span>
             <p className="secondary">Search the stats of any cricket player using his name.</p>
             <form id="search-form" onSubmit={onSubmit}>
                 <input type="text" id="playername" placeholder="Enter player name..."></input>
                 <input type="submit" value="Get Stats"/>
             </form>
             {loading===true && userInput!==null?<Loading />:null}
             {userInput===null?<Alert />:null}
             {players!==null && loading!==true?<Players players={players} selectplayer={getPlayerStat} clear={setPlayers}/>:null}
             {players===null && stat===null && loading===false && userInput!==null?<div id="search-results">
                 <i className="fas fa-user-secret fa-4x"></i>
                 <h1 className="secondary">Search results will appear here..</h1>
                 </div>:null}
             {stat!==null && loading!==true? <Player stat={stat}/>:null}
        </div>
    )
}

export default PlayerSearch
