import React from 'react';
const Players = ({players,selectplayer,clear}) => {

    const getPID =(e)=>{
        const id=e.target.id;
        const pid = players[`${id}`].pid;
        selectplayer(pid);
        clear(null);
    }
    return (
            <div id="players">
                <h1 className="secondary">Player names matched as per your search :</h1>
                {players.map((player,index) =>
                    <div id={index} className="player" onClick={getPID}>
                        <img id={index} className="player-image" src={`https://www.cricapi.com/playerpic/${player.pid}.jpg`} alt="player-img" onError={(e)=>{e.target.src="https://image.flaticon.com/icons/png/512/149/149071.png";e.target.onError=null;}}>
                        </img>
                        <h1 id={index} className="secondary">{player.fullName}</h1></div>                
                )}
            </div>
    )
}

export default Players
